svg.script:
(function () {
  var svg = document.currentScript.ownerDocument.documentElement;
  var partConfig = {
  "wing": {title:"Wing", lines:["The wing supports the aircraft in forward flight like an airplane wing.","Once the rotors tilt forward, the wing carries much of the lift.","This helps the aircraft fly efficiently at higher speed.","The wing is a key difference between tiltrotors and most helicopters."], targets:["wing"], fills:["wing"], labels:["label-wing"]},
  "nacelle": {title:"Nacelle and Rotor", lines:["Each nacelle holds an engine and a rotor system.","The rotor acts like a helicopter rotor in vertical mode.","In forward flight, the nacelle tilts and the rotor acts more like a propeller.","This makes the aircraft capable of both hovering and airplane-like travel."], targets:["nacelle-left-body","rotor-left-hub","rotor-left-v1","rotor-left-v2","nacelle-right-body","rotor-right-hub","rotor-right-v1","rotor-right-v2"], fills:["nacelle-left-body","rotor-left-hub","nacelle-right-body","rotor-right-hub"], labels:["label-nacelle"]},
  "tilt": {title:"Tilt Direction", lines:["These arrows show how the nacelles rotate.","Pointed upward, the rotors provide vertical lift for takeoff and hover.","Tilted forward, the rotors provide forward thrust for airplane-style flight.","That tilting action is the defining feature of a tiltrotor."], targets:["tilt-arrow-left","tilt-arrow-left-head","tilt-arrow-right","tilt-arrow-right-head","nacelle-left-axis","nacelle-right-axis"], fills:[], labels:["label-tilt"]},
  "fuselage": {title:"Fuselage", lines:["The fuselage is the main body of the aircraft.","It carries the crew, passengers, cargo, and central systems.","The wing, tail, and landing gear all connect to it.","It is the structural center of the tiltrotor."], targets:["fuselage"], fills:["fuselage"], labels:["label-fuselage"]},
  "tail": {title:"Tail", lines:["The tail helps keep the aircraft stable and controllable.","It supports directional control in forward flight.","This includes the rear body and vertical stabilizing surfaces.","The tail works together with the wing during airplane-like flight."], targets:["tail","vertical-fin"], fills:["tail","vertical-fin"], labels:["label-tail"]},
  "landing-gear": {title:"Landing Gear", lines:["The landing gear supports the aircraft on the ground.","Wheels allow taxiing, takeoff, and landing operations.","This system must carry the aircraft in both rotorcraft and airplane phases.","It is the ground-support structure of the tiltrotor."], targets:["gear-left","gear-right","wheel-left","wheel-right"], fills:[], labels:["label-landing-gear"]}
};
  var allTargetIds = ["wing","nacelle-left-body","rotor-left-hub","rotor-left-v1","rotor-left-v2","nacelle-right-body","rotor-right-hub","rotor-right-v1","rotor-right-v2","tilt-arrow-left","tilt-arrow-left-head","tilt-arrow-right","tilt-arrow-right-head","nacelle-left-axis","nacelle-right-axis","fuselage","tail","vertical-fin","gear-left","gear-right","wheel-left","wheel-right"];
  var allLabelIds = ["label-wing","label-nacelle","label-tilt","label-fuselage","label-tail","label-landing-gear"];

  function byId(id) { return svg.getElementById(id); }

  function setInfo(title, lines) {
    byId("info-title").textContent = title;
    byId("info-line-1").textContent = lines[0] || "";
    byId("info-line-2").textContent = lines[1] || "";
    byId("info-line-3").textContent = lines[2] || "";
    byId("info-line-4").textContent = lines[3] || "";
  }

  function clearState() {
    allTargetIds.forEach(function(id) {
      var el = byId(id);
      if (el) el.classList.remove("active-stroke","active-fill","active-dashed","dimmed");
    });
    allLabelIds.forEach(function(id) {
      var el = byId(id);
      if (el) el.classList.remove("label-active","dimmed");
    });
  }

  function dimEverything() {
    allTargetIds.forEach(function(id) {
      var el = byId(id);
      if (el) el.classList.add("dimmed");
    });
    allLabelIds.forEach(function(id) {
      var el = byId(id);
      if (el) el.classList.add("dimmed");
    });
  }

  function activatePart(name) {
    var cfg = partConfig[name];
    if (!cfg) return;
    clearState();
    dimEverything();
    cfg.targets.forEach(function(id) {
      var el = byId(id);
      if (!el) return;
      el.classList.remove("dimmed");
      if (id.indexOf("outline") !== -1) el.classList.add("active-dashed");
      else el.classList.add("active-stroke");
    });
    cfg.fills.forEach(function(id) {
      var el = byId(id);
      if (el) el.classList.add("active-fill");
    });
    cfg.labels.forEach(function(id) {
      var el = byId(id);
      if (el) { el.classList.remove("dimmed"); el.classList.add("label-active"); }
    });
    setInfo(cfg.title, cfg.lines);
  }

  Array.prototype.forEach.call(svg.querySelectorAll("[data-part]"), function(node) {
    node.addEventListener("click", function() {
      activatePart(node.getAttribute("data-part"));
    });
  });

  activatePart("tilt");
})();
